head.script:
scwin.selpchClsCd = "1";
scwin.MSG_FS_WRN_013 = "청구 데이타가 존재하지 않습니다.";
scwin.MSG_FS_WRN_014 = "청구취소 데이타가 존재하지 않습니다.";
scwin.MSG_FS_WRN_015 = "청구는 내부거래상태가 등록일때만 가능합니다.";
scwin.MSG_FS_WRN_016 = "청구취소는 내부거래상태가 청구일때만 가능합니다.";
scwin.flag = "";
scwin.bizDom = "";
scwin.selPchLodeptCd = "";
scwin.qryConDt = "";
scwin.qryConLastDt = "";
scwin.acctNm = "";
scwin.strbilgClntNo = "";
scwin.strbilgClntNm = "";
scwin.strlobranCd = "";
scwin.strlobranNm = "";
scwin.privAdmin = "";
scwin.crn = "";
scwin.vLoginCoCd = "";
scwin.vLoginCoClsCd = "";
scwin.vUserHomeClsCd = "";
scwin.isSubCompany = false;
scwin.quantityOfRows = "";
scwin.pageNumber = "1";
scwin.vCoCd = "";
scwin.vCoClsCd = "";
scwin.vCurDate = "";
scwin.strPreDate = "";
scwin.qryConKnd = "";
scwin.txtCoClsCd = "";
scwin.ACConstants_SUBSIDIARY_USER_HOME_CLS_CD = "SA";
scwin.ACConstants_CO_CD_DONGBU = "001";
scwin.ACConstants_CO_CLS_CD_DONGBU = "0";

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    scwin.flag = (scwin.params && scwin.params.flag) ? scwin.params.flag : "";
    scwin.bizDom = (scwin.params && scwin.params.bizDom) ? scwin.params.bizDom : "";
    scwin.selPchLodeptCd = (scwin.params && scwin.params.selPchLodeptCd) ? scwin.params.selPchLodeptCd : "";
    scwin.qryConDt = (scwin.params && scwin.params.qryConDt) ? scwin.params.qryConDt : "";
    scwin.qryConLastDt = (scwin.params && scwin.params.qryConLastDt) ? scwin.params.qryConLastDt : "";
    scwin.acctNm = (scwin.params && scwin.params.acctNm) ? scwin.params.acctNm : "";
    scwin.strbilgClntNo = (scwin.params && scwin.params.bilgClntNo) ? scwin.params.bilgClntNo : "";
    scwin.strbilgClntNm = (scwin.params && scwin.params.bilgClntNm) ? scwin.params.bilgClntNm : "";
    scwin.strlobranCd = (scwin.params && scwin.params.strlobranCd) ? scwin.params.strlobranCd : "";
    scwin.strlobranNm = (scwin.params && scwin.params.strlobranNm) ? scwin.params.strlobranNm : "";
    scwin.crn = (scwin.params && scwin.params.crn) ? scwin.params.crn : "";

    scwin.vLoginCoCd = $c.ses.getCoCd() || "";
    scwin.vLoginCoClsCd = $c.ses.getCoClsCd() || "";
    scwin.vUserHomeClsCd = $c.ses.getUserHomeClsCd() || "";
    scwin.privAdmin = $c.ses.getPrivAdmin() || "";
    scwin.vCoCd = scwin.vLoginCoCd;
    scwin.vCoClsCd = scwin.vLoginCoClsCd;

    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strPreDate = scwin.vCurDate.substring(0, 6) + "01";
};

scwin.onUdcCompleted = async function() {
    ica_qryConDtFm.setValue(scwin.strPreDate);
    ica_qryConDtTo.setValue(scwin.vCurDate);

    scwin.f_setCompanyInfo();

    if (scwin.flag != "") {
        scwin.f_WholeRetrieve();
    }

    if (scwin.selPchLodeptCd != "") {
        scwin.f_executeFromLinked();
    }

    acb_link_qryConKnd.setValue("실적일자");
};

scwin.f_setCompanyInfo = async function() {
    if (scwin.vUserHomeClsCd != scwin.ACConstants_SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = scwin.ACConstants_CO_CD_DONGBU;
        scwin.vLoginCoClsCd = scwin.ACConstants_CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo("T");

    if ("T" == scwin.privAdmin || !scwin.isSubCompany) {
        $c.gus.cfEnableObjects([ed_coCd, txt_coNm]);
    } else {
        $c.gus.cfDisableObjects([ed_coCd, txt_coNm]);
    }
};

scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    udc_co.ilCommonPopUp(scwin.callbackCompanyInfo,
        ed_coCd.getValue(), txt_coNm.getValue(),
        pWinCloseTF, null, null, null, null,
        null, null, null, null, null);
};

scwin.callbackCompanyInfo = async function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);
        txt_coNm.setValue(rtnList[5]);
        scwin.txtCoClsCd = rtnList[1];
    } else {
        ed_coCd.setValue("");
        txt_coNm.setValue("");
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > scwin.ACConstants_CO_CLS_CD_DONGBU) {
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }
};

scwin.f_initObj = async function() {
    $c.gus.cfInitObjects([ed_bilgLodeptCd, txt_bilgLodeptNm]);
    $c.gus.cfInitObjects([ed_bilgClntNo, txt_bilgClntNm]);
};

scwin.f_executeFromLinked = async function() {
    ed_bilgLodeptCd.setValue(scwin.selPchLodeptCd);
    ica_qryConDtFm.setValue(scwin.qryConDt + "01");
    ica_qryConDtTo.setValue(scwin.qryConLastDt);
    scwin.f_Retrieve();
};

scwin.f_WholeRetrieve = async function() {
    ed_bilgLodeptCd.setValue(dma_selldecunsetaggr_con.get("bilgLodeptCd"));
    scwin.f_openCommonPopUp(1, ed_bilgLodeptCd.getValue(), txt_bilgLodeptNm.getValue(), "T", "T");
    ica_qryConDtFm.setValue(dma_selldecunsetaggr_con.get("qryConDtFm"));
    ica_qryConDtTo.setValue(dma_selldecunsetaggr_con.get("qryConDtTo"));
    scwin.f_Retrieve();
};

scwin.f_BizDomRetrieve = async function() {
    ed_bilgLodeptCd.setValue(dma_selldecunsetaggr_con.get("bilgLodeptCd"));
    scwin.f_openCommonPopUp(1, ed_bilgLodeptCd.getValue(), txt_bilgLodeptNm.getValue(), "T", "T");
    ed_bilgClntNo.setValue(dma_selldecunsetaggr_con.get("bilgClntNo"));
    ica_qryConDtFm.setValue(dma_selldecunsetaggr_con.get("qryConDtFm"));
    ica_qryConDtTo.setValue(dma_selldecunsetaggr_con.get("qryConDtTo"));
    scwin.f_Retrieve();
};

scwin.f_Retrieve = async function() {
    let chk = await $c.gus.cfValidate([ed_bilgLodeptCd, ica_qryConDtFm, ica_qryConDtTo]);
    if (!chk) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    dma_selldecunsetaggr_con.set("coCd", ed_coCd.getValue());
    dma_selldecunsetaggr_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue());
    dma_selldecunsetaggr_con.set("bilgClntNo", ed_bilgClntNo.getValue());
    dma_selldecunsetaggr_con.set("qryConDtFm", ica_qryConDtFm.getValue());
    dma_selldecunsetaggr_con.set("qryConDtTo", ica_qryConDtTo.getValue());
    dma_selldecunsetaggr_con.set("regId", ed_regId.getValue());
    dma_selldecunsetaggr_con.set("modId", ed_modId.getValue());
    dma_selldecunsetaggr_con.set("gubun", lc_gubun.getValue());
    dma_selldecunsetaggr_con.set("aggbilgClntNo", ed_bilgClntNo.getValue());
    dma_selldecunsetaggr_con.set("aggsellItemCd", "");
    dma_selldecunsetaggr_con.set("aggtaxnClsCd", "");

    ds_selldecunsetdetail.removeAll();
    spa_totalRow2.setValue(0);

    if (acb_qryConKnd.getValue() == "오더") {
        scwin.qryConKnd = "오더일자";
    } else if (acb_qryConKnd.getValue() == "실적") {
        scwin.qryConKnd = "실적일자";
    } else if (acb_qryConKnd.getValue() == "회계") {
        scwin.qryConKnd = "회계일자";
    } else if (acb_qryConKnd.getValue() == "오더번호") {
        scwin.qryConKnd = "오더번호";
    }

    dma_selldecunsetaggr_con.set("qryConKnd", acb_qryConKnd.getValue());
    dma_selldecunsetaggr_con.set("qryConCd", ed_qryConCd.getValue());

    await $c.sbm.execute(sbm_selldecunsetaggr_retrieve);

    let detailAllChecked = false;
    try {
        detailAllChecked = chb_detailAllYn.getValue() != "";
    } catch(e) {
        detailAllChecked = false;
    }
    if (detailAllChecked) {
        scwin.f_SellingDecDetailRetrieve();
    }
};

scwin.f_save = async function() {
    let confirmResult = await $c.win.confirm(MSG_CM_CRM_001);
    if (confirmResult) {
        if (ds_selldecunsetdetail.isUpdated()) {
            if (!scwin.f_validateSellInfo()) return;
            let valChk = await $c.gus.cfValidate([gr_selldecunsetdetail]);
            if (valChk) {
                await $c.sbm.execute(sbm_saveSellInfo);
            }
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["통합매출일괄수정"]);
        }
    }
};

scwin.f_changeSellInfoWhole = async function() {
    let stPos = ds_selldecunsetdetail.getRowPosition();

    let lcBilgClntNo = ds_selldecunsetdetail.getCellData(stPos, "bilgClntNo");
    let lcBilgClntNm = ds_selldecunsetdetail.getCellData(stPos, "bilgClntNm");
    let lcTaxnClsCd = ds_selldecunsetdetail.getCellData(stPos, "taxnClsCd");
    let lcTsVsslCd = ds_selldecunsetdetail.getCellData(stPos, "tsVsslCd");
    let lcTsPortcnt = ds_selldecunsetdetail.getCellData(stPos, "tsPortcnt");
    let lcBilgIntendDt = ds_selldecunsetdetail.getCellData(stPos, "bilgIntendDt");
    let lcBilgLodeptCd = ds_selldecunsetdetail.getCellData(stPos, "bilgLodeptCd");

    let focusedCol = gr_selldecunsetdetail.getFocusedColumnID ? gr_selldecunsetdetail.getFocusedColumnID() : "";

    for (let i = stPos; i < ds_selldecunsetdetail.getRowCount(); i++) {
        if (ds_selldecunsetdetail.getCellData(i, "dcsnClsCd") != "1") {
            await $c.gus.cfAlertMsg("미확인 내역만 수정이 가능합니다.", []);
            return false;
        }

        if (ds_selldecunsetdetail.getCellData(i, "dcsnClsCd") == "1") {
            ds_selldecunsetdetail.setCellData(i, "chk", "T");
        }

        if (focusedCol == "bilgClntNo" || focusedCol == "bilgClntNm") {
            ds_selldecunsetdetail.setCellData(i, "bilgClntNo", lcBilgClntNo);
            ds_selldecunsetdetail.setCellData(i, "bilgClntNm", lcBilgClntNm);
        }

        if (focusedCol == "taxnClsCd") {
            ds_selldecunsetdetail.setCellData(i, "taxnClsCd", lcTaxnClsCd);
            if (ds_selldecunsetdetail.getCellData(i, "taxnClsCd") == "01") {
                ds_selldecunsetdetail.setCellData(i, "vatAmt", Math.round(ds_selldecunsetdetail.getCellData(i, "sellAmt") * 0.1));
            } else {
                ds_selldecunsetdetail.setCellData(i, "vatAmt", 0);
            }
        }

        if (focusedCol == "vsslCd" || focusedCol == "tsVsslCd" || focusedCol == "tsPortcnt") {
            ds_selldecunsetdetail.setCellData(i, "tsVsslCd", lcTsVsslCd);
            ds_selldecunsetdetail.setCellData(i, "tsPortcnt", lcTsPortcnt);
        }

        if (focusedCol == "bilgIntendDt") {
            ds_selldecunsetdetail.setCellData(i, "bilgIntendDt", lcBilgIntendDt);
        }

        if (focusedCol == "bilgLodeptCd") {
            ds_selldecunsetdetail.setCellData(i, "bilgLodeptCd", lcBilgLodeptCd);
        }
    }
    return true;
};

scwin.f_validateSellInfo = async function() {
    for (let i = 0; i < ds_selldecunsetdetail.getRowCount(); i++) {
        let rowStatus = ds_selldecunsetdetail.getRowStatus(i);
        if (rowStatus != "U") {
            continue;
        }
        if (ds_selldecunsetdetail.getCellData(i, "dcsnClsCd") != "1") {
            await $c.gus.cfAlertMsg("미확인 내역만 수정이 가능합니다.", []);
            return false;
        }
        if ($c.gus.cfIsNull(ds_selldecunsetdetail.getCellData(i, "bilgClntNo"))) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["청구거래처 "]);
            return false;
        }
        if ($c.gus.cfIsNull(ds_selldecunsetdetail.getCellData(i, "bilgLodeptCd"))) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["청구부서 "]);
            return false;
        }
        if ($c.gus.cfIsNull(ds_selldecunsetdetail.getCellData(i, "taxnClsCd"))) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["과세 "]);
            return false;
        }
        if (ds_selldecunsetdetail.getCellData(i, "taxnClsCd") == "01") {
            ds_selldecunsetdetail.setCellData(i, "vatAmt", Math.round(ds_selldecunsetdetail.getCellData(i, "sellAmt") * 0.1));
        } else {
            ds_selldecunsetdetail.setCellData(i, "vatAmt", 0);
        }
    }
    return true;
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let clntNo = ed_bilgClntNo.getValue();

    switch (disGubun) {
        case 1:
            udc_bilgLodept.ilCommonPopUp(scwin.callbackBilgLodept,
                (pCode || "").trim(), pName, pClose, null, null, null, null,
                null, null, null, null, null, null, pAllSearch, null);
            break;
        case 2:
            let param2 = ",,," + ed_coCd.getValue();
            udc_bilgClnt.ilCommonPopUp(scwin.callbackBilgClnt,
                ed_bilgClntNo.getValue().trim(), txt_bilgClntNm.getValue(), pClose, null, null, null, null,
                param2, null, null, null, null);
            break;
        case 5:
            // TODO: 품명코드팝업 - retrieveCommInfo
            break;
        case 6:
            // TODO: B/L코드팝업 - retrieveBlNoList
            break;
        case 7:
            // TODO: 품목코드팝업 - retrieveCommInfo
            break;
        case 10:
            // TODO: 매출항목팝업 - retrieveSelpchItemInfo
            break;
        case 11:
            udc_reg.ilCommonPopUp(scwin.callbackRegId,
                pCode, pName, pClose, null, null, null, null,
                scwin.vLoginCoCd, null, null, null, null, null, pAllSearch,
                "등록자,사용자ID,사용자명");
            break;
        case 14:
            // TODO: B/L코드팝업(OC_HBLH) - retrieveBlNoList2
            break;
        case 15:
            udc_mod.ilCommonPopUp(scwin.callbackModId,
                pCode, pName, pClose, null, null, null, null,
                scwin.vLoginCoCd, null, null, null, null, null, pAllSearch,
                "등록자,사용자ID,사용자명");
            break;
        default:
            break;
    }
};

scwin.callbackBilgLodept = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_bilgLodeptCd, txt_bilgLodeptNm);
};

scwin.callbackBilgClnt = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_bilgClntNo, txt_bilgClntNm);
};

scwin.callbackRegId = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_regId, txt_regNm);
};

scwin.callbackModId = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_modId, txt_modNm);
};

scwin.f_openPopUp = function(flag, check) {
    let qryYear = ica_qryConDtFm.getValue().trim().substring(0, 4);
    let rtnList = [];
    switch (flag) {
        case "1":
            // TODO: 계정조회 - retrieveAcctCdInfo
            break;
        case "3":
            let param3 = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",0";
            udc_bilgLodept.ilCommonPopUp(scwin.callbackDeptPopUp,
                ed_bilgLodeptCd.getValue().trim(), txt_bilgLodeptNm.getValue(), check,
                null, null, null, null, param3, null, null, null, null, null, null, null, null, null, qryYear);
            break;
        case "4":
            let param4 = ",,," + ed_coCd.getValue();
            udc_bilgClnt.ilCommonPopUp(scwin.callbackClntPopUp,
                ed_bilgClntNo.getValue().trim(), txt_bilgClntNm.getValue(), check,
                null, null, null, null, param4, null, null, null, null);
            break;
        case "8":
            // TODO: 사업자번호 - retrieveCrnInfo
            break;
        default:
            break;
    }
};

scwin.callbackDeptPopUp = async function(rtnList) {
    scwin.f_resultPopEd(ed_bilgLodeptCd, txt_bilgLodeptNm, rtnList);
};

scwin.callbackClntPopUp = async function(rtnList) {
    scwin.f_resultPopEd(ed_bilgClntNo, txt_bilgClntNm, rtnList);
};

scwin.f_resultPopEd = async function(strCd, strNm, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }
        strCd.setValue(rtnList[0]);
        strNm.setValue(rtnList[1]);
    } else {
        strCd.setValue("");
        strNm.setValue("");
    }
};

scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    else
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
};

scwin.f_deptPopUp = async function() {
    let param = scwin.vCurDate;
    if (scwin.vCoClsCd > scwin.ACConstants_CO_CLS_CD_DONGBU) {
        param = param + "," + scwin.vCoCd + "," + scwin.vCoClsCd;
    }
    let paramArray = {};
    paramArray.pSelectID = "retrieveAcctDeptCdInfo6";
    paramArray.pCode = ed_bilgLodeptCd;
    paramArray.pName = txt_bilgLodeptNm;
    paramArray.pWhere = param;
    scwin.f_PopUp2(paramArray);
};

scwin.f_PopUp2 = async function(paramArray) {
    let codeObj = paramArray.pCode;
    let nameObj = paramArray.pName;

    let rtnList = $c.gus.cfCommonPopUp(paramArray.pSelectID, $c.gus.cfGetValue(codeObj), "",
        scwin.f_EventCheck(), paramArray.pDispCnt,
        paramArray.pTitle, paramArray.pWidth,
        paramArray.pHidden, paramArray.pWhere,
        paramArray.pW, paramArray.pH,
        paramArray.pTop, paramArray.pLeft,
        paramArray.pExistTF, paramArray.pAllSearchTF,
        paramArray.pWtitleSearch);

    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            $c.gus.cfSetValue(codeObj, rtnList[0]);
            $c.gus.cfSetValue(nameObj, rtnList[1]);
        }
    } else {
        $c.gus.cfSetValue(codeObj, "");
        $c.gus.cfSetValue(nameObj, "");
    }
    return rtnList;
};

scwin.f_EventCheck = async function() {
    return "T";
};

scwin.f_SellingDecDetailRetrieve = async function(row) {
    $c.gus.cfCopyDataSet(dma_selldecunsetaggr_con, dma_selldecunsetdetail_con);

    let detailAllChecked = false;
    try {
        detailAllChecked = chb_detailAllYn.getValue() != "";
    } catch(e) {
        detailAllChecked = false;
    }

    if (detailAllChecked) {
        if (dma_selldecunsetdetail_con.get("aggbilgClntNo") != null
            && dma_selldecunsetdetail_con.get("aggbilgClntNo") != "") {
            let crnChecked = false;
            try {
                crnChecked = chb_crnYn && chb_crnYn.getValue() != "";
            } catch(e) {
                crnChecked = false;
            }
            if (crnChecked) {
                dma_selldecunsetdetail_con.set("crnYn", "Y");
            } else {
                dma_selldecunsetdetail_con.set("crnYn", "N");
            }
        } else {
            dma_selldecunsetdetail_con.set("crnYn", "");
        }
        dma_selldecunsetdetail_con.set("coCd", ed_coCd.getValue());
    } else {
        if (row != undefined && row >= 0) {
            dma_selldecunsetdetail_con.set("aggbilgClntNo", ds_selldecunsetaggr.getCellData(row, "bilgClntNo"));
            dma_selldecunsetdetail_con.set("aggsellItemCd", ds_selldecunsetaggr.getCellData(row, "sellItemCd"));
            dma_selldecunsetdetail_con.set("aggtaxnClsCd", ds_selldecunsetaggr.getCellData(row, "taxnClsCd"));
            dma_selldecunsetdetail_con.set("coCd", ed_coCd.getValue());
        }
    }

    await $c.sbm.execute(sbm_selldecunsetdetail_retrieve);
};

scwin.f_FieldClear = async function() {
    $c.gus.cfInitObjects([ed_bilgLodeptCd, txt_bilgLodeptNm, ica_qryConDtFm, ica_qryConDtTo]);
};

scwin.f_internalTxnStsClsNm = async function(spanId) {
    // TODO: 내부거래상태 보이기 - lc_internalTxnStsClsCd 미존재
};

scwin.f_downExcelSheet = async function(vObjGrd) {
