scwin.f_Print = async function() {
    if (ds_selldecunsetdetail.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let confirmResult = await $c.win.confirm("인쇄하시겠습니까?");
    if (!confirmResult) return;

    let aggrRow = ds_selldecunsetaggr.getRowPosition();
    let odiParam = {};
    odiParam.bilgLodeptCd = ed_bilgLodeptCd.getValue();
    odiParam.bilgClntNo = ed_bilgClntNo.getValue();
    odiParam.qryConDtFm = ica_qryConDtFm.getValue();
    odiParam.qryConDtTo = ica_qryConDtTo.getValue();
    odiParam.aggbilgClntNo = ds_selldecunsetaggr.getCellData(aggrRow, "bilgClntNo");
    odiParam.aggsellItemCd = ds_selldecunsetaggr.getCellData(aggrRow, "sellItemCd");
    odiParam.aggtaxnClsCd = ds_selldecunsetaggr.getCellData(aggrRow, "taxnClsCd");

    if (acb_qryConKnd.getValue() == "오더") {
        scwin.qryConKnd = "오더일자";
    } else if (acb_qryConKnd.getValue() == "실적") {
        scwin.qryConKnd = "실적일자";
    } else if (acb_qryConKnd.getValue() == "회계") {
        scwin.qryConKnd = "회계일자";
    } else if (acb_qryConKnd.getValue() == "오더번호") {
        scwin.qryConKnd = "오더번호";
    }
    odiParam.qryConKnd = scwin.qryConKnd;
    odiParam.bilgLodeptNm = txt_bilgLodeptNm.getValue();
    odiParam.ed_qryConDtFm = ica_qryConDtFm.getValue();
    odiParam.ed_qryConDtTo = ica_qryConDtTo.getValue();
    odiParam.bilgClntNm = txt_bilgClntNm.getValue();
    odiParam.coCd = ed_coCd.getValue();
    odiParam.gubun = lc_gubun.getValue();

    // TODO: cfOZReport 호출 - OZ Report 연동
    $c.gus.cfOZReport("chb_printCheck", "chb_previewCheck", "/ds/fs/fs_204_02_04p.ozr", odiParam, {}, {});
};

