scwin.sbm_selldecunsetdetail_retrieve_submitdone = async function(e) {
    spa_totalRow2.setValue(ds_selldecunsetdetail.getRowCount());
    if (ds_selldecunsetdetail.getRowCount() > 0) {
        gr_selldecunsetdetail.setFocusedCell(0, "odrNo");
    }

    let size20 = 0;
    let size40 = 0;
    let size45 = 0;
    for (let i = 0; i < ds_selldecunsetdetail.getRowCount(); i++) {
        let cntrSize = ds_selldecunsetdetail.getCellData(i, "cntrSizCd");
        if (cntrSize == "20") {
            ++size20;
        } else if (cntrSize == "40") {
            ++size40;
        } else {
            ++size45;
        }
    }
    let sizeCntTxt = "20_SIZE " + size20 + "건, 40_SIZE " + size40 + "건";
};

